@page "/book-appointment"
@rendermode InteractiveServer
@using sv_47fa8e72b9d9487fb3755f9f6cf0dc8d.Models
@using sv_47fa8e72b9d9487fb3755f9f6cf0dc8d.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

<EditForm EditContext="editContext" OnSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ── STEP 1: Patient Info ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="model.Name" />
            <ValidationMessage For="() => model.Name" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="AdvanceToStep2">Next</button>
        }
    </fieldset>

    @* ── STEP 2: Appointment Details ── *@
    @if (showStep2)
    {
        <hr class="my-4" />
        <fieldset>
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="model.Doctor" @bind:after="OnDoctorChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Date</label>
                <InputDate class="form-control" @bind-Value="model.Date" @bind:after="OnDateChanged" />
                <ValidationMessage For="() => model.Date" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
                <ValidationMessage For="() => model.Reason" />
            </div>

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Checking..." : "Check Availability")
            </button>
        </fieldset>
    }
</EditForm>

@if (isConfirmed)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool isConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    private static readonly string[] step1Fields = [nameof(AppointmentFormModel.Name),
        nameof(AppointmentFormModel.Email), nameof(AppointmentFormModel.Phone),
        nameof(AppointmentFormModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void AdvanceToStep2()
    {
        // Validate only step 1 fields
        editContext.Validate();
        var hasStep1Errors = step1Fields
            .Any(f => editContext.GetValidationMessages(editContext.Field(f)).Any());

        if (!hasStep1Errors)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorChanged() => await LoadSlotsAsync();
    private async Task OnDateChanged() => await LoadSlotsAsync();

    private async Task LoadSlotsAsync()
    {
        if (model.Doctor is not null && model.Date.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(model.Doctor, model.Date.Value);
        }
        else
        {
            availableSlots = [];
        }
        model.TimeSlot = null;
    }

    private async Task HandleSubmit()
    {
        if (!editContext.Validate()) return;

        // Additional required checks for step 2 fields
        var step2Errors = new Dictionary<string, List<string>>();
        if (string.IsNullOrWhiteSpace(model.Doctor))
            step2Errors["Doctor"] = ["Please select a doctor."];
        if (!model.Date.HasValue)
            step2Errors["Date"] = ["Date is required."];
        if (string.IsNullOrWhiteSpace(model.TimeSlot))
            step2Errors["TimeSlot"] = ["Please select a time slot."];
        if (string.IsNullOrWhiteSpace(model.Reason))
            step2Errors["Reason"] = ["Reason for visit is required."];

        if (step2Errors.Count > 0)
        {
            customValidator!.DisplayErrors(step2Errors);
            return;
        }

        isSubmitting = true;
        customValidator!.ClearErrors();

        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator.DisplayErrors(errors);
                return;
            }

            isConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

